// ── Helpers (easybits Extractor output) ────────────────────────────
// Extractor wraps everything in a `data` envelope and returns the
// STRING "null" for missing fields, arrays as JSON-encoded or
// comma-separated strings.
const d = $input.first().json.data;

function isMissing(v) {
  return v === undefined || v === null || v === 'null' || v === '';
}

function toArray(v) {
  if (isMissing(v)) return [];
  if (Array.isArray(v)) return v.map(x => String(x).trim()).filter(Boolean);
  if (typeof v === 'string') {
    const s = v.trim();
    if (s.startsWith('[')) {                 // JSON-encoded array
      try {
        const parsed = JSON.parse(s);
        if (Array.isArray(parsed)) return parsed.map(x => String(x).trim()).filter(Boolean);
      } catch (e) { /* fall through to comma-split */ }
    }
    return s.split(',').map(x => x.trim()).filter(Boolean);   // comma-split fallback
  }
  return [v];
}

const get = (k) => (isMissing(d[k]) ? '' : String(d[k]).trim());

// ── Build one candidate row (same schema as CV onboarding output) ──
return [{
  json: {
    name:                   get('name'),
    current_title:          get('current_title'),
    current_company:        get('current_company'),
    location:               get('location'),
    total_years_experience: get('total_years_experience'),
    top_skills:             toArray(d.top_skills).join(', '),
    last_roles:             toArray(d.last_roles).join(' | '),
    education:              get('education'),
    certifications:         toArray(d.certifications).join(', '),
    summary:                get('summary'),
    // ── provenance: this is the field that makes the "one database,
    //    two intake paths" story work. CV onboarding writes "CV (applicant)".
    source:                 'LinkedIn (sourced)',
    added_at:               new Date().toISOString(),
  }
}];

