const newCandidate = $('Normalize: Candidate Fields').first().json;
const existingRows = $input.all()
  .map(item => item.json)
  .filter(row => row && row.name);   // ignore the empty-item case

const normalize = (s) => String(s || '').trim().toLowerCase();
const key = (row) => normalize(row.name) + '|' + normalize(row.current_company);
const newKey = key(newCandidate);

const duplicate = existingRows.find(row => key(row) === newKey);

return [{
  json: {
    ...newCandidate,
    is_duplicate: Boolean(duplicate),
    existing_added_at: duplicate
      ? new Date(duplicate.added_at).toLocaleDateString('en-US', { year: 'numeric', month: 'short', day: 'numeric' })
      : null,
  }
}];

